// git_history.cpp
//
// Git commit history building and graph visualization
//
// This module contains:
// - SHA conversion utilities (sha_raw_to_hex; hex_to_sha lives in git_objects.cpp)
// - Commit history building (git_history_build)
// - Graph lane calculation for visualization
//
// Public API:
