#include "app.h"
#include "ui_theme.h"

static_assert(Git::MAX_HISTORY_COMMITS <= 65535,
    "commit_index is uint16_t; widen GitHistory::ShaIndex::commit_index if raising MAX_HISTORY_COMMITS");

// ============================================================================
// Commit History Building
// ============================================================================

// Helper: Check if raw SHA is all zeros
static bool sha_raw_is_zero(const uint8_t* sha) {
    for (size_t i = 0; i < Git::SHA1_RAW_SIZE; i++) {
        if (sha[i] != 0) return false;
    }
    return true;
}

// Helper: Convert raw SHA to hex string
static void sha_raw_to_hex(const uint8_t* raw, char* hex) {
    for (size_t i = 0; i < Git::SHA1_RAW_SIZE; i++) {
        sprintf_s(hex + i * 2, 3, "%02x", raw[i]);
    }
    hex[Git::SHA1_HEX_SIZE] = '\0';
}

// Comparison function for SHA index qsort/bsearch
static int sha_index_compare(const void* a, const void* b) {
    const GitHistory::ShaIndex* ia = static_cast<const GitHistory::ShaIndex*>(a);
    const GitHistory::ShaIndex* ib = static_cast<const GitHistory::ShaIndex*>(b);
    return memcmp(ia->sha, ib->sha, Git::SHA1_RAW_SIZE);
}

// Lane assignment state
struct LaneState {
    uint8_t sha[Git::SHA1_RAW_SIZE];   // SHA currently occupying this lane
    bool active;                         // Lane is in use
    uint8_t color_index;                 // Color for this lane
};

// Build SHA index from commits array for binary search
static void build_sha_index(GitHistory* history) {
    for (size_t i = 0; i < history->commit_count; i++) {
        memcpy(history->sha_index[i].sha, history->commits[i].sha, Git::SHA1_RAW_SIZE);
        history->sha_index[i].commit_index = static_cast<uint16_t>(i);
    }
    history->sha_index_count = history->commit_count;
    qsort(history->sha_index, history->sha_index_count, sizeof(GitHistory::ShaIndex), sha_index_compare);
}

// Find commit index by raw SHA (binary search)
int git_history_find_sha(const GitHistory* history, const uint8_t* sha_raw) {
    if (!history || !sha_raw || history->sha_index_count == 0) return -1;

    GitHistory::ShaIndex key;
    memcpy(key.sha, sha_raw, Git::SHA1_RAW_SIZE);

    GitHistory::ShaIndex* found = static_cast<GitHistory::ShaIndex*>(
        bsearch(&key, history->sha_index, history->sha_index_count,
                sizeof(GitHistory::ShaIndex), sha_index_compare));

    return found ? static_cast<int>(found->commit_index) : -1;
}

// Find commit index by hex SHA
int git_history_find_sha_hex(const GitHistory* history, const char* sha_hex) {
    if (!history || !sha_hex || strlen(sha_hex) < Git::SHA1_HEX_SIZE) return -1;

    uint8_t sha_raw[Git::SHA1_RAW_SIZE];
    hex_to_sha(sha_hex, sha_raw);
    return git_history_find_sha(history, sha_raw);
}

// Get message first line for a commit
const char* git_history_get_message(const GitHistory* history, size_t index) {
    if (!history || index >= history->commit_count) return "";
    const CommitMeta* meta = &history->commits[index];
    if (meta->message_offset >= history->message_buffer_size) return "";
    return &history->message_buffer[meta->message_offset];
}

// Get author name for a commit
const char* git_history_get_author(const GitHistory* history, size_t index) {
    if (!history || index >= history->commit_count) return "";
    const CommitMeta* meta = &history->commits[index];
    if (meta->author_offset >= history->author_buffer_size) return "";
    return &history->author_buffer[meta->author_offset];
}

// Get hex SHA for a commit
void git_history_get_sha_hex(const GitHistory* history, size_t index, char* out_sha_hex) {
    if (!history || index >= history->commit_count || !out_sha_hex) {
        if (out_sha_hex) out_sha_hex[0] = '\0';
        return;
    }
    sha_raw_to_hex(history->commits[index].sha, out_sha_hex);
}

// Set active lane bits in graph node
static void set_lane_active(GraphNode* node, int lane) {
    if (lane < 0 || lane >= 32) return;
    if (lane < 8) node->active_lane_mask_low |= (1 << lane);
    else if (lane < 16) node->active_lane_mask_mid |= (1 << (lane - 8));
    else if (lane < 24) node->active_lane_mask_high |= (1 << (lane - 16));
    else node->active_lane_mask_top |= (1 << (lane - 24));
}

// Calculate graph lanes for all commits
static void calculate_graph_lanes(GitHistory* history) {
    if (!history || history->commit_count == 0) return;

    LaneState lanes[Git::MAX_LANES] = {};
    int active_lane_count = 0;
    int next_color = 0;

    bool lane_overflow_warned = false;
    // Helper to find a free lane
    auto allocate_lane = [&](const uint8_t* sha, int preferred = -1) -> int {
        // Try preferred lane first
        if (preferred >= 0 && preferred < (int)Git::MAX_LANES && !lanes[preferred].active) {
            lanes[preferred].active = true;
            memcpy(lanes[preferred].sha, sha, Git::SHA1_RAW_SIZE);
            lanes[preferred].color_index = next_color++ % 5;
            active_lane_count++;
            return preferred;
        }
        // Find first free lane
        for (int i = 0; i < (int)Git::MAX_LANES; i++) {
            if (!lanes[i].active) {
                lanes[i].active = true;
                memcpy(lanes[i].sha, sha, Git::SHA1_RAW_SIZE);
                lanes[i].color_index = next_color++ % 5;
                active_lane_count++;
                return i;
            }
        }
        if (!lane_overflow_warned) {
            LOG_WARN("calculate_graph_lanes: all %d lanes occupied; commit assigned off-screen lane -1", (int)Git::MAX_LANES);
            lane_overflow_warned = true;
        }
        return -1;
    };

    // Helper to find which lane a SHA occupies
    auto find_lane_for_sha = [&](const uint8_t* sha) -> int {
        for (int i = 0; i < (int)Git::MAX_LANES; i++) {
            if (lanes[i].active && memcmp(lanes[i].sha, sha, Git::SHA1_RAW_SIZE) == 0) {
                return i;
            }
        }
        return -1;
    };

    // Helper to reserve a lane for a SHA (update who owns it)
    auto reserve_lane = [&](int lane, const uint8_t* sha) {
        if (lane >= 0 && lane < (int)Git::MAX_LANES) {
            memcpy(lanes[lane].sha, sha, Git::SHA1_RAW_SIZE);
        }
    };

    // Helper to free a lane
    auto free_lane = [&](int lane) {
        if (lane >= 0 && lane < (int)Git::MAX_LANES && lanes[lane].active) {
            lanes[lane].active = false;
            memset(lanes[lane].sha, 0, Git::SHA1_RAW_SIZE);
            active_lane_count--;
        }
    };

    // Process each commit in topological order (newest to oldest)
    for (size_t i = 0; i < history->commit_count; i++) {
        CommitMeta* meta = &history->commits[i];
        GraphNode* node = &history->graph[i];

        // Initialize graph node
        node->lane = -1;
        node->flags = 0;
        node->color_index = 0;
        node->active_lane_mask_low = 0;
        node->active_lane_mask_mid = 0;
        node->active_lane_mask_high = 0;
        node->active_lane_mask_top = 0;
        node->parent1.target_lane = -1;
        node->parent1.target_row = UINT16_MAX;
        node->parent2.target_lane = -1;
        node->parent2.target_row = UINT16_MAX;

        // Find which lane this commit should be on
        int assigned_lane = find_lane_for_sha(meta->sha);

        if (assigned_lane < 0) {
            // No child claimed this lane - this is a branch tip (start of a new lane)
            assigned_lane = allocate_lane(meta->sha);
            node->flags |= GraphNodeFlags::LANE_START;
        }

        node->lane = static_cast<int8_t>(assigned_lane);
        if (assigned_lane >= 0) {
            node->color_index = lanes[assigned_lane].color_index;
        }

        // Record active lanes at this row
        for (int l = 0; l < (int)Git::MAX_LANES; l++) {
            if (lanes[l].active) {
                set_lane_active(node, l);
            }
        }

        // Track max lane used
        if (assigned_lane > history->max_lane_used) {
            history->max_lane_used = assigned_lane;
        }

        // Handle first parent
        // With first-parent-priority sorting, main branch is processed first,
        // so it naturally claims common ancestors before feature branches.
        bool lane_continues = false;
        if (meta->parent_count >= 1 && !sha_raw_is_zero(meta->parent_sha)) {
            int parent_idx = git_history_find_sha(history, meta->parent_sha);

            if (parent_idx >= 0 && parent_idx > (int)i) {
                // Parent is in our history (later row since we're newest-first)
                node->parent1.target_row = static_cast<uint16_t>(parent_idx);
                lane_continues = true;

                // Check if parent already has a lane assigned
                int parent_lane = find_lane_for_sha(meta->parent_sha);
                if (parent_lane >= 0) {
                    // Parent already has lane (claimed by main branch first due to sorting)
                    node->parent1.target_lane = static_cast<int8_t>(parent_lane);
                    if (parent_lane != assigned_lane) {
                        // Our lane merges into parent's lane
                        node->flags |= GraphNodeFlags::LANE_END;
                        free_lane(assigned_lane);
                        lane_continues = false;
                    }
                } else {
                    // Reserve our lane for the first parent (continuation)
                    reserve_lane(assigned_lane, meta->parent_sha);
                    node->parent1.target_lane = static_cast<int8_t>(assigned_lane);
                }
            } else {
                // Parent not in history - this is an end point
                node->flags |= GraphNodeFlags::LANE_END;
                free_lane(assigned_lane);
            }
        } else if (meta->parent_count == 0) {
            // Root commit - free the lane
            node->flags |= GraphNodeFlags::LANE_END;
            free_lane(assigned_lane);
        }

        // Handle second parent (merge commit)
        if (meta->parent_count >= 2 && !sha_raw_is_zero(meta->parent2_sha)) {
            meta->flags |= CommitMetaFlags::IS_MERGE;

            int parent2_idx = git_history_find_sha(history, meta->parent2_sha);
            if (parent2_idx >= 0 && parent2_idx > (int)i) {
                // Second parent is in our history
                node->parent2.target_row = static_cast<uint16_t>(parent2_idx);

                int parent2_lane = find_lane_for_sha(meta->parent2_sha);
                if (parent2_lane >= 0) {
                    // Second parent already has a lane from another merge
                    node->parent2.target_lane = static_cast<int8_t>(parent2_lane);
                } else {
                    // Allocate new lane for second parent branch
                    int new_lane = allocate_lane(meta->parent2_sha);
                    node->parent2.target_lane = static_cast<int8_t>(new_lane);
                }

                // Set merge direction flags
                if (node->parent2.target_lane < assigned_lane) {
                    node->flags |= GraphNodeFlags::MERGE_LEFT;
                } else if (node->parent2.target_lane > assigned_lane) {
                    node->flags |= GraphNodeFlags::MERGE_RIGHT;
                }
            }
            // Note: if parent2 is NOT in history, we don't allocate a lane for it
            // because we won't be drawing that branch at all
        }
    }
}

// Free history data
void git_history_free(GitHistory* history) {
    if (!history) return;

    delete[] history->commits;
    delete[] history->graph;
    delete[] history->message_buffer;
    delete[] history->author_buffer;
    delete[] history->sha_index;

    memset(history, 0, sizeof(GitHistory));
}

// Build commit history from repository using temporal topological sort
// This ensures: 1) children before parents (topological), 2) newest first when possible (temporal)
bool git_history_build(GitRepository* repo, GitHistory* out_history) {
    if (!repo || !repo->is_valid || !out_history) return false;

    // Require a valid HEAD SHA (40 hex chars). Unborn branches / empty repos have no history.
    if (strlen(repo->head_sha) < Git::SHA1_HEX_SIZE) return false;

    // Clear any existing history
    git_history_free(out_history);
    memset(out_history, 0, sizeof(GitHistory));

    // Allocate arrays
    size_t capacity = Git::MAX_HISTORY_COMMITS;
    out_history->commits = new CommitMeta[capacity];
    out_history->graph = new GraphNode[capacity];
    out_history->sha_index = new GitHistory::ShaIndex[capacity];
    out_history->capacity = capacity;

    // Allocate string buffers
    size_t msg_buffer_capacity = capacity * (Git::MESSAGE_FIRST_LINE_MAX + 1);
    size_t author_buffer_capacity = capacity * 64;
    out_history->message_buffer = new char[msg_buffer_capacity];
    out_history->author_buffer = new char[author_buffer_capacity];
    out_history->message_buffer_size = 0;
    out_history->author_buffer_size = 0;

    // Initialize arrays
    memset(out_history->commits, 0, sizeof(CommitMeta) * capacity);
    memset(out_history->graph, 0, sizeof(GraphNode) * capacity);

    // =============================================================
    // PHASE 1: Collect all commits via BFS into a temporary buffer
    // =============================================================
    struct TempCommit {
        CommitMeta meta;
        char message[Git::MESSAGE_FIRST_LINE_MAX + 1];
        char author[64];
        int in_degree;  // Number of children in our set (for topo sort)
    };
    TempCommit* temp_commits = new TempCommit[capacity];
    size_t temp_count = 0;

    struct QueueEntry { uint8_t sha[Git::SHA1_RAW_SIZE]; };
    constexpr size_t QUEUE_SIZE = 8192;
    QueueEntry* queue = new QueueEntry[QUEUE_SIZE];
    size_t queue_head = 0, queue_tail = 0, queue_count = 0;
    size_t queue_dropped = 0;

    // Open-addressed hash map: SHA -> index in temp_commits. Sized to next pow2 >=
    // 2*capacity so load factor stays <= 0.5 and probe chains stay short. Replaces
    // the previous O(N) linear scan find_temp_idx, which made the BFS visited
    // check + in-degree calc + topo sort all O(N^2).
    size_t sha_map_size = 1;
    while (sha_map_size < capacity * 2) sha_map_size *= 2;
    size_t sha_map_mask = sha_map_size - 1;
    int32_t* sha_map = new int32_t[sha_map_size];
    for (size_t i = 0; i < sha_map_size; i++) sha_map[i] = -1;

    auto sha_to_hash = [](const uint8_t* sha) -> uint32_t {
        // The SHA is already a uniformly distributed hash; the first 4 bytes are
        // good enough for the table.
        return (uint32_t)sha[0] | ((uint32_t)sha[1] << 8) |
               ((uint32_t)sha[2] << 16) | ((uint32_t)sha[3] << 24);
    };

    auto find_temp_idx = [&](const uint8_t* sha) -> int {
        size_t idx = sha_to_hash(sha) & sha_map_mask;
        size_t probed = 0;
        while (probed < sha_map_size) {
            int32_t v = sha_map[idx];
            if (v < 0) return -1;
            if (memcmp(temp_commits[v].meta.sha, sha, Git::SHA1_RAW_SIZE) == 0) {
                return v;
            }
            idx = (idx + 1) & sha_map_mask;
            probed++;
        }
        return -1;
    };

    auto insert_temp_idx = [&](const uint8_t* sha, int32_t value) {
        size_t idx = sha_to_hash(sha) & sha_map_mask;
        for (;;) {
            if (sha_map[idx] < 0) { sha_map[idx] = value; return; }
            idx = (idx + 1) & sha_map_mask;
        }
    };

    // Start BFS from HEAD
    uint8_t head_sha_raw[Git::SHA1_RAW_SIZE];
    hex_to_sha(repo->head_sha, head_sha_raw);
    memcpy(queue[queue_tail++ % QUEUE_SIZE].sha, head_sha_raw, Git::SHA1_RAW_SIZE);
    queue_count++;

    while (queue_head != queue_tail && temp_count < capacity) {
        uint8_t current_sha[Git::SHA1_RAW_SIZE];
        memcpy(current_sha, queue[queue_head % QUEUE_SIZE].sha, Git::SHA1_RAW_SIZE);
        queue_head++;
        queue_count--;

        if (find_temp_idx(current_sha) >= 0) continue;  // Already visited

        char sha_hex[Git::SHA1_HEX_SIZE + 1];
        sha_raw_to_hex(current_sha, sha_hex);

        GitCommit full_commit = {};
        if (!git_read_commit(repo, sha_hex, &full_commit)) continue;

        TempCommit* tc = &temp_commits[temp_count];
        memset(tc, 0, sizeof(TempCommit));
        memcpy(tc->meta.sha, current_sha, Git::SHA1_RAW_SIZE);
        tc->meta.timestamp = full_commit.author_time;
        tc->in_degree = 0;  // Will be calculated in phase 2

        // Store parents
        tc->meta.parent_count = 0;
        if (full_commit.parent_sha[0]) {
            hex_to_sha(full_commit.parent_sha, tc->meta.parent_sha);
            tc->meta.parent_count++;
            if (queue_count < QUEUE_SIZE - 1) {
                memcpy(queue[queue_tail % QUEUE_SIZE].sha, tc->meta.parent_sha, Git::SHA1_RAW_SIZE);
                queue_tail++;
                queue_count++;
            } else {
                queue_dropped++;
            }
        }
        // TODO(octopus): git_read_commit only surfaces parent_sha/parent2_sha; commits with
        // 3+ parents (octopus merges) silently drop parents 3+. git_read_commit_parents() in
        // git_commit.cpp is static and not reachable here without a forward declaration.
        // CommitMeta structure change required to fix properly - defer until then.
        if (full_commit.parent2_sha[0]) {
            hex_to_sha(full_commit.parent2_sha, tc->meta.parent2_sha);
            tc->meta.parent_count++;
            tc->meta.flags |= CommitMetaFlags::IS_MERGE;
            if (queue_count < QUEUE_SIZE - 1) {
                memcpy(queue[queue_tail % QUEUE_SIZE].sha, tc->meta.parent2_sha, Git::SHA1_RAW_SIZE);
                queue_tail++;
                queue_count++;
            } else {
                queue_dropped++;
            }
        }

        // Store message (first line)
        const char* msg = full_commit.message;
        const char* newline = strchr(msg, '\n');
        size_t msg_len = newline ? (size_t)(newline - msg) : strlen(msg);
        if (msg_len > Git::MESSAGE_FIRST_LINE_MAX) msg_len = Git::MESSAGE_FIRST_LINE_MAX;
        memcpy(tc->message, msg, msg_len);
        tc->message[msg_len] = '\0';
        tc->meta.message_len = static_cast<uint16_t>(msg_len);

        // Store author
        size_t author_len = strlen(full_commit.author_name);
        if (author_len > 63) author_len = 63;
        memcpy(tc->author, full_commit.author_name, author_len);
        tc->author[author_len] = '\0';
        tc->meta.author_len = static_cast<uint8_t>(author_len);

        insert_temp_idx(tc->meta.sha, static_cast<int32_t>(temp_count));
        temp_count++;
    }
    delete[] queue;

    if (queue_dropped > 0) {
        LOG_WARN("git_history_build: BFS queue full, dropped %zu parent enqueue(s) - history may be incomplete", queue_dropped);
    }

    if (temp_count == 0) {
        delete[] sha_map;
        delete[] temp_commits;
        git_history_free(out_history);
        return false;
    }

    // =============================================================
    // PHASE 2: Calculate in-degrees AND mark first-parent chain
    // First-parent chain gets priority in sorting to ensure main branch
    // is processed before feature branches (so main claims ancestors first)
    // =============================================================
    bool* is_first_parent = new bool[temp_count];
    memset(is_first_parent, 0, temp_count * sizeof(bool));

    // Mark first-parent chain from HEAD (index 0 after BFS)
    {
        int idx = 0;  // Start from HEAD
        while (idx >= 0 && idx < (int)temp_count) {
            is_first_parent[idx] = true;
            TempCommit* tc = &temp_commits[idx];
            if (tc->meta.parent_count >= 1 && !sha_raw_is_zero(tc->meta.parent_sha)) {
                idx = find_temp_idx(tc->meta.parent_sha);
            } else {
                break;
            }
        }
    }

    // Calculate in-degrees
    for (size_t i = 0; i < temp_count; i++) {
        TempCommit* tc = &temp_commits[i];
        if (tc->meta.parent_count >= 1 && !sha_raw_is_zero(tc->meta.parent_sha)) {
            int parent_idx = find_temp_idx(tc->meta.parent_sha);
            if (parent_idx >= 0) temp_commits[parent_idx].in_degree++;
        }
        if (tc->meta.parent_count >= 2 && !sha_raw_is_zero(tc->meta.parent2_sha)) {
            int parent_idx = find_temp_idx(tc->meta.parent2_sha);
            if (parent_idx >= 0) temp_commits[parent_idx].in_degree++;
        }
    }

    // =============================================================
    // PHASE 3: Temporal Topological Sort with First-Parent Priority (Kahn's
    // algorithm using a binary max-heap). Priority key, lexicographically:
    //   (1) is_first_parent (true beats false)
    //   (2) timestamp (newer beats older)
    // Previously this was an O(N^2) full-scan-per-emit; now O(N log N).
    // =============================================================
    size_t* sorted_indices = new size_t[temp_count];
    size_t sorted_count = 0;

    // Heap stores temp_commits indices; comparisons use the helpers below.
    int32_t* heap = new int32_t[temp_count];
    size_t heap_size = 0;

    auto heap_better = [&](int32_t a, int32_t b) -> bool {
        // Returns true if `a` should pop before `b`.
        bool a_fp = is_first_parent[a];
        bool b_fp = is_first_parent[b];
        if (a_fp != b_fp) return a_fp;  // first-parent wins
        return temp_commits[a].meta.timestamp > temp_commits[b].meta.timestamp;
    };

    auto heap_push = [&](int32_t idx) {
        size_t i = heap_size++;
        heap[i] = idx;
        // Sift up
        while (i > 0) {
            size_t parent = (i - 1) / 2;
            if (heap_better(heap[i], heap[parent])) {
                int32_t tmp = heap[i]; heap[i] = heap[parent]; heap[parent] = tmp;
                i = parent;
            } else break;
        }
    };

    auto heap_pop = [&]() -> int32_t {
        int32_t top = heap[0];
        heap_size--;
        if (heap_size > 0) {
            heap[0] = heap[heap_size];
            // Sift down
            size_t i = 0;
            for (;;) {
                size_t l = 2 * i + 1;
                size_t r = 2 * i + 2;
                size_t best = i;
                if (l < heap_size && heap_better(heap[l], heap[best])) best = l;
                if (r < heap_size && heap_better(heap[r], heap[best])) best = r;
                if (best == i) break;
                int32_t tmp = heap[i]; heap[i] = heap[best]; heap[best] = tmp;
                i = best;
            }
        }
        return top;
    };

    // Seed heap with all commits that already have in_degree==0.
    for (size_t i = 0; i < temp_count; i++) {
        if (temp_commits[i].in_degree == 0) heap_push(static_cast<int32_t>(i));
    }

    while (heap_size > 0) {
        int32_t best_idx = heap_pop();
        sorted_indices[sorted_count++] = static_cast<size_t>(best_idx);

        // Decrement in_degree of parents; push them once they hit zero.
        TempCommit* tc = &temp_commits[best_idx];
        if (tc->meta.parent_count >= 1 && !sha_raw_is_zero(tc->meta.parent_sha)) {
            int parent_idx = find_temp_idx(tc->meta.parent_sha);
            if (parent_idx >= 0) {
                if (--temp_commits[parent_idx].in_degree == 0) {
                    heap_push(parent_idx);
                }
            }
        }
        if (tc->meta.parent_count >= 2 && !sha_raw_is_zero(tc->meta.parent2_sha)) {
            int parent_idx = find_temp_idx(tc->meta.parent2_sha);
            if (parent_idx >= 0) {
                if (--temp_commits[parent_idx].in_degree == 0) {
                    heap_push(parent_idx);
                }
            }
        }
    }
    delete[] heap;
    delete[] is_first_parent;
    delete[] sha_map;

    // =============================================================
    // PHASE 4: Copy sorted commits to output arrays
    // =============================================================
    for (size_t i = 0; i < sorted_count; i++) {
        TempCommit* tc = &temp_commits[sorted_indices[i]];
        CommitMeta* meta = &out_history->commits[i];

        // Copy metadata
        *meta = tc->meta;

        // Copy message to buffer
        size_t msg_len = strlen(tc->message);
        if (out_history->message_buffer_size + msg_len + 1 < msg_buffer_capacity) {
            meta->message_offset = static_cast<uint32_t>(out_history->message_buffer_size);
            memcpy(&out_history->message_buffer[out_history->message_buffer_size], tc->message, msg_len + 1);
            out_history->message_buffer_size += msg_len + 1;
        } else {
            meta->message_offset = UINT32_MAX;
            meta->message_len = 0;
        }

        // Copy author to buffer
        size_t author_len = strlen(tc->author);
        if (out_history->author_buffer_size + author_len + 1 < author_buffer_capacity) {
            meta->author_offset = static_cast<uint16_t>(out_history->author_buffer_size);
            memcpy(&out_history->author_buffer[out_history->author_buffer_size], tc->author, author_len + 1);
            out_history->author_buffer_size += author_len + 1;
        } else {
            meta->author_offset = UINT16_MAX;
            meta->author_len = 0;
        }

        // Mark HEAD (first commit in sorted output)
        if (i == 0) {
            meta->flags |= CommitMetaFlags::IS_HEAD;
        } else {
            meta->flags &= ~CommitMetaFlags::IS_HEAD;
        }
    }
    out_history->commit_count = sorted_count;

    delete[] sorted_indices;
    delete[] temp_commits;

    // Build SHA index for fast lookups
    build_sha_index(out_history);

    // Calculate graph lanes (now works correctly with temporal topological order)
    calculate_graph_lanes(out_history);

    out_history->generation++;
    out_history->is_valid = true;

    return true;
}

